usepackage("amsmath");

unitsize(1 cm);

pair A, B, O, P, Q, V;

A = (1,2);
B = (2,-1);
O = (0,0);
V = (3,-3);
P = (V + reflect(O,A)*(V))/2;

draw(O--V,Arrow(6));
draw(O--P,Arrow(6));
draw(P--V,Arrow(6));
