draw((0,-4)--(0,1));

label("$\begin{pmatrix} 3 \\ -3 \end{pmatrix}$", V, SE);
label("$\begin{pmatrix} -\frac{3}{5} \\ -\frac{6}{5} \end{pmatrix}$", P, W);
[/asy]

